/**
 * Amazon Listing Linkage Engine
 * Evaluates complex boolean expressions generated by the backend
 */

export function evaluateLinkageExpression(expression: string, attributes: Record<string, any>): boolean {
  if (!expression) return false;

  try {
    // 1. Transform Amazon's .contains() to JS .includes() and handle null checks
    const jsExpr = expression.replace(/\.contains\(/g, '.includes(');

    // 2. Identify all potential field identifiers in the expression
    // Matches field names like 'parentage_level.0.value'
    const idRegex = /([a-zA-Z_][a-zA-Z0-9_\.]*)/g;
    const reserved = ['true', 'false', 'null', 'undefined', 'includes'];
    
    const fieldNames = new Set<string>();
    let match;
    while ((match = idRegex.exec(jsExpr)) !== null) {
      if (!reserved.includes(match[1])) {
        fieldNames.add(match[1]);
      }
    }

    // 3. Resolve actual values for each field
    const fieldValues: Record<string, any> = {};
    
    const normalize = (val: any): any => {
      if (val === undefined || val === null) return null;
      
      // Amazon SP-API structure normalization:
      // Try to extract the 'value' property if it exists (Leaf Node wrapper)
      if (Array.isArray(val)) {
        if (val.length === 0) return null;
        const first = val[0];
        if (typeof first === 'object' && first !== null && first.value !== undefined) return first.value;
        return first;
      }
      if (typeof val === 'object' && val !== null && val.value !== undefined) return val.value;
      return val;
    };

    const extractVal = (fieldId: string) => {
      // 1. Direct match (backwards compatibility for flat attributes)
      if (attributes[fieldId] !== undefined) return normalize(attributes[fieldId]);

      // 2. Deep traversal for nested structures (Option A)
      const parts = fieldId.split('.');
      let current: any = attributes;
      for (const part of parts) {
        if (current === null || current === undefined || typeof current !== 'object') {
          current = null;
          break;
        }
        current = current[part];
      }
      
      return normalize(current);
    };

    // 4. Create a safe evaluation environment
    // Map dots in field names to underscores for JS variable names
    const varMap: Record<string, any> = {};
    let finalExpr = jsExpr;
    
    // Sort field names by length descending to avoid replacing substrings (e.g., 'a.b' before 'a')
    const sortedFields = Array.from(fieldNames).sort((a, b) => b.length - a.length);
    
    sortedFields.forEach(field => {
      const safeVar = 'f_' + field.replace(/\./g, '_');
      varMap[safeVar] = extractVal(field);
      
      // Use negative lookahead/lookbehind to ensure we match the full identifier 
      // and not a substring of another identifier (especially handling the dot)
      const escapedField = field.replace(/\./g, '\\.');
      // Matches the field ONLY if it's not preceded or followed by an identifier character (including dots)
      const fieldRegex = new RegExp('(?<![a-zA-Z0-9_\\.])' + escapedField + '(?![a-zA-Z0-9_\\.])', 'g');
      finalExpr = finalExpr.replace(fieldRegex, safeVar);
    });

    // 5. Execute evaluation
    const fn = new Function(...Object.keys(varMap), `return (${finalExpr});`);
    return !!fn(...Object.values(varMap));
  } catch (e) {
    console.warn('[AMZ Linkage] Eval failed:', expression, e);
    return false;
  }
}
